import boto3
import json
from botocore.exceptions import BotoCoreError, ClientError

# Specify your AWS region and the queue name
AWS_REGION = 'your-region'
QUEUE_NAME = 'your-queue-name'

def get_queue(sqs):
    try:
        response = sqs.get_queue_url(QueueName=QUEUE_NAME)
    except ClientError as error:
        print("Couldn't find queue", QUEUE_NAME, ". Message: ", str(error))
        raise error
    else:
        return sqs.Queue(response['QueueUrl'])

def process_message(message):
    # parse message body here and execute actions based on the content of the message
    print("Received message: " + message)

def poll_sqs():
    try:
        sqs = boto3.resource('sqs', region_name=AWS_REGION)
        queue = get_queue(sqs)
        
        while True:
            messages = queue.receive_messages(WaitTimeSeconds=20, MaxNumberOfMessages=10)
            
            if not messages:
                print("No new message received")
                continue
                
            for message in messages:
                # parse the json content of a message
                try:
                    process_message(json.loads(message.body))
                except json.JSONDecodeError:
                    print('Failed to decode JSON')
                    
                # delete processed message from queue    
                message.delete()  
    except BotoCoreError as error:
        print("Couldn't poll SQS queue", QUEUE_NAME, ". Message: ", str(error))
        raise error
        
if __name__ == "__main__":
    poll_sqs()